use tokio::time::{sleep, Duration};

#[tokio::main]
async fn main() {
    let handle1 = tokio::spawn(async {
        sleep(Duration::from_millis(100)).await;
        "task 1 done"
    });

    let handle2 = tokio::spawn(async {
        sleep(Duration::from_millis(50)).await;
        "task 2 done"
    });

    // Both tasks run concurrently
    let result1 = handle1.await.unwrap();
    let result2 = handle2.await.unwrap();
    println!("{}, {}", result1, result2);
}

use tokio::time::{sleep, Duration};

async fn fetch_user() -> String {
    sleep(Duration::from_millis(100)).await;
    "Alice".to_string()
}

async fn fetch_orders() -> Vec<String> {
    sleep(Duration::from_millis(150)).await;
    vec!["order-1".to_string(), "order-2".to_string()]
}

#[tokio::main]
async fn main() {
    // Run both concurrently, wait for both to complete
    let (user, orders) = tokio::join!(fetch_user(), fetch_orders());
    println!("User: {}, Orders: {:?}", user, orders);
}

use std::sync::Arc;
use tokio::sync::Mutex;

#[tokio::main]
async fn main() {
    let counter = Arc::new(Mutex::new(0u64));
    let mut handles = vec![];

    for i in 0..5 {
        let counter = Arc::clone(&counter);
        handles.push(tokio::spawn(async move {
            let mut lock = counter.lock().await;
            *lock += 1;
            println!("Task {} incremented counter to {}", i, *lock);
        }));
    }

    for handle in handles {
        handle.await.unwrap();
    }

    println!("Final: {}", *counter.lock().await);
}

use tokio::task::JoinSet;

#[tokio::main]
async fn main() {
    let mut set = JoinSet::new();

    for i in 0..5 {
        set.spawn(async move {
            tokio::time::sleep(tokio::time::Duration::from_millis(i * 50)).await;
            i * 10
        });
    }

    while let Some(result) = set.join_next().await {
        match result {
            Ok(value) => println!("Task returned: {}", value),
            Err(e) => println!("Task failed: {}", e),
        }
    }
}
